import anthropic

client = anthropic.Anthropic()


def call(prompt: str, max_tokens: int = 400) -> str:
    return client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=max_tokens,
        temperature=0.0,
        messages=[{"role": "user", "content": prompt}],
    ).content[0].text.strip()


def classify_strategy(question: str) -> str:
    """
    Route a question to the best answering strategy.
    Returns one of: 'direct', 'cot', 'step_back', 'step_back_cot'.
    """
    prompt = (
        "Classify the best prompting strategy for the question below.\n"
        "Return ONLY one of these four labels, nothing else:\n"
        "  direct         — simple fact lookup; no reasoning chain needed\n"
        "  cot            — sequential arithmetic or logic; no principle to retrieve\n"
        "  step_back      — requires recalling a general principle or concept\n"
        "  step_back_cot  — requires recalling a formula AND multi-step computation\n"
        f"\nQuestion: {question}"
    )
    return call(prompt, max_tokens=10).strip().lower()


def answer(question: str, abstract_q: str | None = None) -> str:
    strategy = classify_strategy(question)

    if strategy == "direct":
        return call(question)

    if strategy == "cot":
        return call(f"{question}\nLet's think step by step.")

    if strategy in ("step_back", "step_back_cot") and abstract_q:
        principle = call(
            f"Answer this general question in 2 sentences:\n{abstract_q}"
        )
        suffix = "Show each step." if strategy == "step_back_cot" else ""
        return call(
            f"Principle: {principle}\n\n"
            f"Using this principle, answer:\n{question}\n{suffix}"
        )

    # Fallback when no abstract_q is provided for step-back variants:
    # generate the abstraction automatically
    auto_abstract = call(
        f"Write one general question that covers the underlying concept needed to "
        f"answer:\n{question}"
    )
    principle = call(f"Answer in 2 sentences:\n{auto_abstract}")
    return call(f"Principle: {principle}\n\nAnswer:\n{question}")


SAMPLES = [
    ("What is the capital of France?", None),
    ("If 30% of 200 is X, what is X + 50?", None),
    ("Why does ice float on water?", "What physical property causes some substances to be less dense as solids than as liquids?"),
    ("A metal rod of 2 m expands by 0.003 m when heated 100°C. Find the coefficient of linear expansion.",
     "What is the formula for thermal linear expansion?"),
]

for q, aq in SAMPLES:
    strategy = classify_strategy(q)
    print(f"Strategy: {strategy}")
    print(f"Q: {q}")
    print(f"A: {answer(q, aq)[:200]}")
    print()
